+              if (isExpandable && willEnable) {
+                setExpandedFields((prev) => {
+                  const next = new Set(prev);
+                  next.add(field.name);
+                  return next;
+                });
+              }
+            }}
+            onClick={(e) => e.stopPropagation()}
