+  return (
+    <ErrorBoundary>
+      <StyledWrapper>
+        <div className="query-builder-search">
+          <input
+            type="text"
+            placeholder="Search operations..."
+            value={searchText}
+            onChange={(e) => setSearchText(e.target.value)}
