+    setEnabledArgs((prev) => {
+      const next = new Set(prev);
+      if (enabling) {
+        next.add(fullKey);
+        const suffix = fullKey.slice(fieldPath.length + 1);
+        const parts = suffix.split('.');
+        for (let i = 1; i < parts.length; i++) {
+          next.add(`${fieldPath}.${parts.slice(0, i).join('.')}`);
+        }
+      } else {
+        next.delete(fullKey);
+        deleteSetByPrefix(next, fullKey);
+      }
+      return next;
+    });
+
+    if (enabling) {
+      setSelections((prev) => {
+        if (prev.has(fieldPath)) return prev;
+        const next = new Set(prev);
+        next.add(fieldPath);
+        ensureAncestorsSelected(next, fieldPath);
+        return next;
+      });
+    } else {
+      setArgValues((prev) => {
+        const next = new Map(prev);
+        deleteMapByPrefix(next, fullKey);
+        return next;
+      });
+    }
+  }, []);
+
+  const setInputFieldValue = useCallback((fullKey, value) => {
+    updateArgValue(fullKey, value);
+  }, [updateArgValue]);
+
+  return {
+    selections,
+    expandedPaths,
+    argValues,
+    enabledArgs,
+    availableRootTypes,
+    syncError,
+    toggleField,
+    toggleExpand,
+    toggleArg,
+    setArgValue,
+    toggleInputField,
+    setInputFieldValue
+  };
+}
