+
+  return {
+    name: field.name,
+    path,
+    type: field.type,
+    namedType: named,
+    typeLabel: getTypeLabel(field.type),
+    isLeaf: isLeafType(field.type),
+    isDeprecated: field.isDeprecated || false,
