+          if (s.startsWith(memberPath + '.')) {
+            isMemberSelected = true;
+            break;
+          }
+        }
+      }
+      if (!isMemberSelected) continue;
+      collectVariablesFromSelections(selections, enabledArgs, memberType, memberPath, nextVisited, depth + 1, varMap, usedNames);
+    }
+    return;
+  }
