+          kind: Kind.ARGUMENT,
+          name: { kind: Kind.NAME, value: arg.name },
+          value: objValue
+        });
+      }
+    } else {
+      const varInfo = varMap.get(key);
+      if (varInfo) {
+        args.push({
+          kind: Kind.ARGUMENT,
+          name: { kind: Kind.NAME, value: arg.name },
+          value: { kind: Kind.VARIABLE, name: { kind: Kind.NAME, value: varInfo.varName } }
+        });
+      }
+    }
+  }
