+  const variableValues = {};
+  for (const [argKey, { varName, type }] of varMap) {
+    variableDefinitions.push({
+      kind: Kind.VARIABLE_DEFINITION,
+      variable: { kind: Kind.VARIABLE, name: { kind: Kind.NAME, value: varName } },
+      type: typeToAST(type)
