+  const document = {
+    kind: Kind.DOCUMENT,
+    definitions: [
+      {
+        kind: Kind.OPERATION_DEFINITION,
+        operation,
+        name: { kind: Kind.NAME, value: operationName },
+        variableDefinitions: variableDefinitions.length > 0 ? variableDefinitions : undefined,
+        selectionSet
+      }
+    ]
+  };
