+  test('rename a message via double-click', async ({ pageWithUserData: page }) => {
+    await openRequest(page, COLLECTION_NAME, MULTI_MSG_REQ);
+
+    const messageLabel = page.getByTestId('ws-message-label-0');
+    await messageLabel.dblclick();
+
