+const getEditorScroll = async (page: Page, selector: string): Promise<number> => {
+  const editor = page.locator(selector).first();
+  return editor.evaluate((el) => {
+    const cm = (el as any).CodeMirror;
+    if (!cm) return 0;
+    const info = cm.getScrollInfo();
+    return info?.top ?? 0;
+  });
+};
