+    const item = this.all().findLast((i) => HeaderList.#ciEquals(i.key, name));
+    return item ? item.value : undefined;
+  }
+
+  /**
+   * Get the full header object by key (case-insensitive).
+   * @param {string} name
+   * @returns {object|undefined}
+   */
